INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (1, 'serendipity', 'noun', 'sự may mắn không dự định', 'The discovery of penicillin was a result of serendipity.', 'Persian, from the title of a fairy tale ''The Three Princes'' Adventure in Many Lands''', 'The word ''serendipity'' was coined in 1754 by Horace Walpole, who used it in a letter to a friend.', '2026-03-11 17:00:00.000+00', '2026-03-06 04:18:08.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (2, 'serendipity', 'noun', 'thần tiên bất ngờ', 'The discovery of penicillin was a result of serendipity.', 'Persian, from the story ''The Three Princes of Serendip''', 'The word ''serendipity'' was coined in 1754 by Horace Walpole, who was trying to remember the name of the Persian fairy tale where the princes kept finding good fortune unexpectedly.', '2026-03-12 17:00:00.000+00', '2026-03-03 03:31:32.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (3, 'serendipity', 'noun', 'ngẫu nhiên may mắn', 'The discovery of penicillin was a result of serendipity.', 'From the Persian fairy tale ''The Three Princes of Serendip'', where the heroes made fortunate discoveries without seeking them.', 'Serendipity is derived from the name of an ancient kingdom in South Asia, Serendip.', '2026-03-13 17:00:00.000+00', '2026-02-27 05:08:00.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (4, 'serendipity', 'noun', 'thông tin bất ngờ', 'The discovery of penicillin was a result of serendipity.', 'Persian (سرندیپ, serendip, a fairy in a fairy tale)', 'The word was coined in 1754 by the author Horace Walpole, who claimed to have invented it while reading an Arabian Nights story.', '2026-03-14 17:00:00.000+00', '2026-03-14 11:04:52.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (5, 'serendipity', 'noun', 'ngẫu nhiên may mắn', 'The discovery of penicillin was a result of serendipity.', 'Persian, from sarandip, meaning ''land of happy chance'' or ''fortunate island''', 'The word ''serendipity'' was coined by Horace Walpole in a letter in 1754.', '2026-03-15 17:00:00.000+00', '2026-03-06 06:05:49.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (6, 'serendipity', 'noun', 'thần kỳ', 'The discovery of penicillin was a result of serendipity.', 'From the Persian fairy tale ''The Three Princes of Serendip'', where ''Serendip'' is an old name for Sri Lanka.', 'The word ''serendipity'' was coined in 1754 by the British author Horace Walpole.', '2026-03-16 17:00:00.000+00', '2026-03-17 05:13:42.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (7, 'serendipity', 'noun', 'sự may mắn không ngờ', 'The discovery of the new species was a result of pure serendipity.', 'Persian, from serendip, mythical island in fairy tale, where fortunate discoveries are made', 'The word ''serendipity'' was coined by Horace Walpole in a letter to a friend in 1754.', '2026-03-17 17:00:00.000+00', '2026-03-02 02:57:45.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (8, 'serendipity', 'noun', 'sự may mắn bất ngờ', 'The discovery of penicillin was a serendipity that changed medical history.', 'The term was coined by the 18th-century author Horace Walpole, derived from Persian fairy tales.', 'Serendipity is derived from the title of a Persian fairy tale ''The Three Princes of Serendip'', where Serendip is an ancient name for Sri Lanka.', '2026-03-18 17:00:00.000+00', '2026-02-27 09:32:48.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (9, 'serendipity', 'noun', 'tuynhệt may mắn bất ngờ', 'The discovery of penicillin was a classic example of serendipity.', 'Persian, originally meaning ''three pronged spear''', 'The word ''serendipity'' was coined by the English author Horace Walpole in a letter to a friend in 1754.', '2026-03-19 17:00:00.000+00', '2026-03-03 02:04:05.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (10, 'serendipity', 'noun', 'dự định may mắn', 'The discovery of penicillin was a result of serendipity.', 'From the Persian fairy tale ''The Three Princes of Serendip''.', 'The word ''serendipity'' was coined in the 18th century by Horace Walpole.', '2026-03-20 17:00:00.000+00', '2026-03-17 03:40:40.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (11, 'serendipity', 'noun', 'ý nghịch ngợp, may mắn không ngờ', 'The serendipity of meeting an old friend on a rainy day added a special touch to my week.', 'Persian, originally ''serendipity'' means the good fortune of the protagonist in a fairy tale of Persian origin.', 'The word ''serendipity'' was coined in 1754 by British author Horace Walpole, inspired by a Persian fairy tale called ''The Three Princes of Serendip''.', '2026-03-21 17:00:00.000+00', '2026-03-02 11:01:23.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (12, 'serendipity', 'noun', 'tiên duyên', 'The discovery of the new species was a result of serendipity, as the researcher was actually looking for something else.', 'Persian and English, from the fairy tale ''The Three Princes of Serendip'', meaning the ability to make fortunate discoveries by accident.', 'The word ''serendipity'' was coined by Horace Walpole, an 18th-century English writer, in a letter to a friend.', '2026-03-22 17:00:00.000+00', '2026-03-08 04:49:32.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (13, 'Serendipity', 'noun', 'Duyên may', 'The serendipity of meeting an old friend in a foreign city was truly delightful.', 'Persian, from ''serendipit'' meaning ''happy fortune'' in the fairy tale ''The Three Princes of Serendip''.', 'The word ''serendipity'' was coined in 1754 by Horace Walpole, a British author.', '2026-03-23 17:00:00.000+00', '2026-03-12 11:57:15.000+00');
INSERT INTO public.daily_word ("id", "word", "part_of_speech", "vietnamese_translation", "example", "origin", "fun_fact", "target_date", "created_at") VALUES (14, 'serendipity', 'noun', 'ngẫu nhiên đẹp mắt', 'The discovery of penicillin was a result of serendipity.', 'Persian, originally meaning ''three young princesses''', 'The word ''serendipity'' was coined by Horace Walpole in 1754.', '2026-03-24 17:00:00.000+00', '2026-03-03 10:56:41.000+00');
INSERT INTO public.source ("id", "user_id", "type", "title", "url", "content", "raw_html", "raw_text", "file_path", "metadata", "deleted_at", "created_at", "updated_at") VALUES (1, 13, 'note', 'Learning English Basics', NULL, '{"paragraphs":["In English, the use of the subjunctive mood is often misunderstood. It is typically used to express wishes, suggestions, or hypothetical situations. For example, ''I suggest that he be given a chance'' or ''It is essential that she be informed.'' Note the verb ''be'' in these sentences, which is a hallmark of the subjunctive.","Learning about the British Isles can enrich your understanding of English culture. Each country or region has its own dialects and sayings. For instance, in Scotland, you might hear ''Aye'' instead of ''Yes,'' and in Ireland, ''Grand'' is used to mean ''good'' or ''well.'' Exploring these differences can make your English more nuanced and interesting."]}'::jsonb, NULL, 'In English, the use of the subjunctive mood is often misunderstood. It is typically used to express wishes, suggestions, or hypothetical situations. For example, ''I suggest that he be given a chance'' or ''It is essential that she be informed.'' Note the verb ''be'' in these sentences, which is a hallmark of the subjunctive.
INSERT INTO public.source ("id", "user_id", "type", "title", "url", "content", "raw_html", "raw_text", "file_path", "metadata", "deleted_at", "created_at", "updated_at") VALUES (2, 11, 'pdf', 'Essential English Learning Guide', NULL, '{"text":"In English grammar, a clause is a group of words containing a subject and a predicate. The subject is typically the person, place, thing, or idea that is doing or being something, while the predicate tells what the subject is doing. For example, in the sentence \"The cat sleeps on the mat,\" \"the cat\" is the subject, and \"sleeps on the mat\" is the predicate."}'::jsonb, NULL, 'In English grammar, a clause is a group of words containing a subject and a predicate. The subject is typically the person, place, thing, or idea that is doing or being something, while the predicate tells what the subject is doing. For example, in the sentence "The cat sleeps on the mat," "the cat" is the subject, and "sleeps on the mat" is the predicate.', '/uploads/pdf/2.pdf', '{"pages":44}'::jsonb, NULL, '2026-01-24 05:52:24.000+00', '2026-03-12 08:50:37.000+00');
INSERT INTO public.source ("id", "user_id", "type", "title", "url", "content", "raw_html", "raw_text", "file_path", "metadata", "deleted_at", "created_at", "updated_at") VALUES (3, 11, 'txt', 'Learning English Basics', NULL, '{"text":"1. Start with the basics: Focus on mastering fundamental grammar rules and common vocabulary.\n2. Practice regularly: Consistency is key in learning a new language. Even short daily practice sessions are beneficial.\n3. Use apps and online resources: There are numerous free and paid resources available online to enhance your learning experience.\n4. Listen to English: Watch movies, TV shows, and listen to podcasts or music in English to improve your listening skills.\n5. Read in English: Start with children''s books or simplified texts and gradually move to more complex materials.\n6. Write in English: Keeping a journal or writing short stories can help improve your writing skills and vocabulary.\n7. Join a language exchange: Find a native English speaker willing to help you practice"}'::jsonb, NULL, '1. Start with the basics: Focus on mastering fundamental grammar rules and common vocabulary.
INSERT INTO public.source ("id", "user_id", "type", "title", "url", "content", "raw_html", "raw_text", "file_path", "metadata", "deleted_at", "created_at", "updated_at") VALUES (4, 13, 'book', 'Unlocking English: A Comprehensive Guide', NULL, '{"excerpt":"As I flipped through the pages of my new English textbook, I felt a mix of excitement and trepidation. Excitement because this was my ticket to a world of endless possibilities, where I could communicate with people from all corners of the globe. Trepidation because I knew the journey ahead wouldn''t be easy. The first lesson was titled \"Greetings and Introductions,\" which seemed simple enough. I started by learning the basic phrases like \"Hello, how are you?\" and \"My name is...\". Each phrase was accompanied by a helpful audio clip so I could hear the correct pronunciation. I practiced these phrases in the mirror, mimicking the tones and intonations as best as I could. It was a small step, but"}'::jsonb, NULL, 'As I flipped through the pages of my new English textbook, I felt a mix of excitement and trepidation. Excitement because this was my ticket to a world of endless possibilities, where I could communicate with people from all corners of the globe. Trepidation because I knew the journey ahead wouldn''t be easy. The first lesson was titled "Greetings and Introductions," which seemed simple enough. I started by learning the basic phrases like "Hello, how are you?" and "My name is...". Each phrase was accompanied by a helpful audio clip so I could hear the correct pronunciation. I practiced these phrases in the mirror, mimicking the tones and intonations as best as I could. It was a small step, but', NULL, '{"author":"David Brown","year":2013}'::jsonb, NULL, '2026-03-10 08:53:40.000+00', '2026-03-11 07:36:43.000+00');
INSERT INTO public.source ("id", "user_id", "type", "title", "url", "content", "raw_html", "raw_text", "file_path", "metadata", "deleted_at", "created_at", "updated_at") VALUES (5, 2, 'note', 'Tips for Effective English Learning', NULL, '{"paragraphs":["In English, the use of the subjunctive mood often appears in expressions such as ''suggest,'' ''demand,'' ''require,'' and ''insist,'' where the subjunctive form is typically used after these verbs. For example, ''He suggested that she be the project leader.'' This usage emphasizes the necessity or desire expressed by the speaker.","Learning about English idioms can greatly enhance your ability to communicate naturally. Idioms, such as ''it''s raining cats and dogs,'' are phrases that have figurative meanings different from the literal ones. Understanding these expressions enriches your vocabulary and helps in expressing yourself more effectively in daily conversations."]}'::jsonb, NULL, 'In English, the use of the subjunctive mood often appears in expressions such as ''suggest,'' ''demand,'' ''require,'' and ''insist,'' where the subjunctive form is typically used after these verbs. For example, ''He suggested that she be the project leader.'' This usage emphasizes the necessity or desire expressed by the speaker.
INSERT INTO public.source ("id", "user_id", "type", "title", "url", "content", "raw_html", "raw_text", "file_path", "metadata", "deleted_at", "created_at", "updated_at") VALUES (6, 13, 'link', 'Explore English: Beginner Basics', 'https://example.com/explore-english-beginner-basics', '{"summary":"The article emphasizes the importance of consistent practice and exposure to authentic English content for effective language learning. It also suggests using various resources like apps, podcasts, and videos to make learning more engaging and convenient."}'::jsonb, '<html><body>The article emphasizes the importance of consistent practice and exposure to authentic English content for effective language learning. It also suggests using various resources like apps, podcasts, and videos to make learning more engaging and convenient.</body></html>', 'The article emphasizes the importance of consistent practice and exposure to authentic English content for effective language learning. It also suggests using various resources like apps, podcasts, and videos to make learning more engaging and convenient.', NULL, '{"url":"https://example.com/article6"}'::jsonb, NULL, '2026-01-23 14:20:05.000+00', '2026-03-06 04:28:16.000+00');
INSERT INTO public.source ("id", "user_id", "type", "title", "url", "content", "raw_html", "raw_text", "file_path", "metadata", "deleted_at", "created_at", "updated_at") VALUES (7, 12, 'link', 'Tips for Effective English Learning', 'https://example.com/tips-for-effective-english-learning', '{"summary":"The article emphasizes the importance of consistent practice and utilizing a variety of resources, such as apps, videos, and books, to effectively learn English. It also highlights the significance of immersing oneself in English-speaking environments, whether virtually or in person, to enhance language skills and confidence."}'::jsonb, '<html><body>The article emphasizes the importance of consistent practice and utilizing a variety of resources, such as apps, videos, and books, to effectively learn English. It also highlights the significance of immersing oneself in English-speaking environments, whether virtually or in person, to enhance language skills and confidence.</body></html>', 'The article emphasizes the importance of consistent practice and utilizing a variety of resources, such as apps, videos, and books, to effectively learn English. It also highlights the significance of immersing oneself in English-speaking environments, whether virtually or in person, to enhance language skills and confidence.', NULL, '{"url":"https://example.com/article7"}'::jsonb, NULL, '2026-02-15 09:06:46.000+00', '2026-03-05 14:06:03.000+00');
INSERT INTO public.source ("id", "user_id", "type", "title", "url", "content", "raw_html", "raw_text", "file_path", "metadata", "deleted_at", "created_at", "updated_at") VALUES (8, 6, 'book', 'Unlocking English', NULL, '{"excerpt":"In the quiet of her study, Sarah flipped through the pages of her latest English learning book, her eyes dancing over the new vocabulary she aimed to master. Today, she had set her focus on adjectives and the subtle art of describing objects and people with vivid clarity. She picked up a pen, her mind buzzing with ideas, and began to jot down sentences that would soon fill her notebook. \"The golden sunlight bathed the tranquil lake, reflecting the serene sky above.\" Each word chosen carefully, each sentence crafted with thought, Sarah felt the depth of her language expanding like ripples in a pond."}'::jsonb, NULL, 'In the quiet of her study, Sarah flipped through the pages of her latest English learning book, her eyes dancing over the new vocabulary she aimed to master. Today, she had set her focus on adjectives and the subtle art of describing objects and people with vivid clarity. She picked up a pen, her mind buzzing with ideas, and began to jot down sentences that would soon fill her notebook. "The golden sunlight bathed the tranquil lake, reflecting the serene sky above." Each word chosen carefully, each sentence crafted with thought, Sarah felt the depth of her language expanding like ripples in a pond.', NULL, '{"author":"John Smith","year":2005}'::jsonb, '2026-03-16 13:20:38.000+00', '2026-03-13 12:47:22.000+00', '2026-03-15 12:30:08.000+00');
INSERT INTO public.source ("id", "user_id", "type", "title", "url", "content", "raw_html", "raw_text", "file_path", "metadata", "deleted_at", "created_at", "updated_at") VALUES (9, 12, 'book', 'Mastering English: A Comprehensive Guide', NULL, '{"excerpt":"In the quiet of her study, Mia flipped through her notebook, each page filled with new phrases and vocabulary she was determined to master. Today, she focused on the simple present tense, a cornerstone of everyday conversation. \"I love reading,\" she wrote, followed by \"She plays the piano beautifully.\" Each sentence was a step towards fluency, a small victory in her ongoing journey to improve her English skills. With a satisfied nod, she moved on to the next exercise, ready to tackle the challenges that lay ahead."}'::jsonb, NULL, 'In the quiet of her study, Mia flipped through her notebook, each page filled with new phrases and vocabulary she was determined to master. Today, she focused on the simple present tense, a cornerstone of everyday conversation. "I love reading," she wrote, followed by "She plays the piano beautifully." Each sentence was a step towards fluency, a small victory in her ongoing journey to improve her English skills. With a satisfied nod, she moved on to the next exercise, ready to tackle the challenges that lay ahead.', NULL, '{"author":"Jane Doe","year":2020}'::jsonb, NULL, '2026-02-15 15:10:08.000+00', '2026-03-08 11:12:46.000+00');
INSERT INTO public.source ("id", "user_id", "type", "title", "url", "content", "raw_html", "raw_text", "file_path", "metadata", "deleted_at", "created_at", "updated_at") VALUES (10, 3, 'link', 'Learn English Fundamentals Online', 'https://example.com/learn-english-fundamentals-online', '{"summary":"The article discusses the importance of consistent practice and suggests using daily podcasts and news articles to improve listening and reading skills. It also recommends joining online English-speaking communities to enhance conversation and vocabulary skills."}'::jsonb, '<html><body>The article discusses the importance of consistent practice and suggests using daily podcasts and news articles to improve listening and reading skills. It also recommends joining online English-speaking communities to enhance conversation and vocabulary skills.</body></html>', 'The article discusses the importance of consistent practice and suggests using daily podcasts and news articles to improve listening and reading skills. It also recommends joining online English-speaking communities to enhance conversation and vocabulary skills.', NULL, '{"url":"https://example.com/article10"}'::jsonb, NULL, '2026-02-09 09:12:55.000+00', '2026-03-09 12:02:57.000+00');
INSERT INTO public.source ("id", "user_id", "type", "title", "url", "content", "raw_html", "raw_text", "file_path", "metadata", "deleted_at", "created_at", "updated_at") VALUES (11, 5, 'note', 'Learning English Basics', NULL, '{"paragraphs":["In English, the subjunctive mood is often used to express wishes, suggestions, or hypothetical situations. For example, ''I suggest that he be more patient'' or ''It is crucial that she be informed.'' This mood is formed using ''be'' for all subjects in the present tense and the base form of the verb for all other tenses.","Understanding British culture is essential for effective communication in English-speaking countries. British humor, for instance, often relies on irony and sarcasm, which can be challenging for non-native speakers. To better understand British humor, it''s helpful to be familiar with common phrases like ''cheeky'' and ''mate'', which are frequently used in casual conversation."]}'::jsonb, NULL, 'In English, the subjunctive mood is often used to express wishes, suggestions, or hypothetical situations. For example, ''I suggest that he be more patient'' or ''It is crucial that she be informed.'' This mood is formed using ''be'' for all subjects in the present tense and the base form of the verb for all other tenses.
INSERT INTO public.source ("id", "user_id", "type", "title", "url", "content", "raw_html", "raw_text", "file_path", "metadata", "deleted_at", "created_at", "updated_at") VALUES (12, 3, 'txt', 'English Learning Journey', NULL, '{"text":"1. Practice Regularly: Consistency is key in learning English. Set aside a few minutes each day to practice, whether it’s reading a book, watching a movie, or engaging in conversation.\n\n2. Build Vocabulary: Expand your word power by learning new words daily. Use flashcards, apps, or a small notebook to jot down new terms and their meanings.\n\n3. Listen Actively: Listen to English-language podcasts, music, or news to improve your listening skills. Pay attention to how words are pronounced and try to mimic the intonation.\n\n4. Read Widely: Read English books, articles, or blogs to enhance your comprehension and vocabulary. Start with simpler texts and gradually move to more complex materials.\n\n5. Write Regularly:"}'::jsonb, NULL, '1. Practice Regularly: Consistency is key in learning English. Set aside a few minutes each day to practice, whether it’s reading a book, watching a movie, or engaging in conversation.
