INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (1, 8, 'fill_blank', 'The ___________ of the sentence is the part that expresses the main idea.', 'The predicate of the sentence includes the verb and its complements, expressing the main action or state of the subject.', '{"answers":["predicate"],"keywords":["sentence","main idea"]}'::jsonb, '2026-02-15 15:10:35.000+00', '2026-03-18 10:47:26.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (2, 13, 'matching', 'Match the English words with their meanings:', 'Select the correct meaning for each word from the list.', '{"pairs":[{"id":1,"left":"Amiable","right":"Friendly and pleasant"},{"id":2,"left":"Cacophony","right":"A harsh, unpleasant sound"},{"id":3,"left":"Furtive","right":"Done in a secretive or stealthy manner"},{"id":4,"left":"Lethargic","right":"Feeling or showing a lack of energy and enthusiasm"},{"id":5,"left":"Vex","right":"Trouble or annoy (someone)"}]}'::jsonb, '2026-02-23 09:10:58.000+00', '2026-03-16 11:42:34.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (3, 10, 'ordering', 'Arrange the following steps of the water cycle in the correct order: evaporation, precipitation, condensation, collection.', 'The correct order of the water cycle is evaporation, condensation, precipitation, and collection. This is the natural sequence in which water moves through the environment.', '{"type":"ordering","items":[{"text":"evaporation","order_id":1},{"text":"condensation","order_id":2},{"text":"precipitation","order_id":3},{"text":"collection","order_id":4}]}'::jsonb, '2026-01-24 12:00:03.000+00', '2026-03-17 14:00:02.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (4, 2, 'ordering', 'Arrange the sentences in the correct order to form a coherent paragraph about starting a day.', 'The correct order helps in understanding the sequence of activities typically followed in starting a day.', '{"ordering":{"items":[{"text":"Get out of bed","order_id":1},{"text":"Eat breakfast","order_id":2},{"text":"Take a shower","order_id":3},{"text":"Go to work/school","order_id":4}]}}'::jsonb, '2026-02-02 10:00:24.000+00', '2026-03-02 06:11:44.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (5, 2, 'matching', 'Match the following English phrasal verbs with their meanings:', 'The correct matches are based on the common meanings of the phrasal verbs.', '{"type":"matching","pairs":[{"id":1,"left":"break down","right":"to fail or stop working"},{"id":2,"left":"turn down","right":"to refuse or reject"},{"id":3,"left":"hand in","right":"to submit or deliver"},{"id":4,"left":"look up","right":"to search for information"},{"id":5,"left":"take off","right":"to leave or depart"}]}'::jsonb, '2026-02-09 09:51:34.000+00', '2026-03-11 09:24:35.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (6, 3, 'single_choice', 'Which of the following words means ''to make something new or different''?', 'The word ''innovate'' means to introduce new ideas, methods, or products, making something new or different.', '{"options":[{"id":"a","text":"innovate"},{"id":"b","text":"interrupt"},{"id":"c","text":"inspire"},{"id":"d","text":"invent"}],"correctAnswers":["a"]}'::jsonb, '2026-02-04 11:16:55.000+00', '2026-02-28 07:35:20.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (7, 15, 'matching', 'Match the following English prepositions with their correct meanings:', 'Correct matches will align the prepositions with their appropriate definitions, which is essential for proper sentence construction and comprehension.', '{"pairs":[{"id":1,"left":"in","right":"inside a container or position"},{"id":2,"left":"on","right":"touching the surface of"},{"id":3,"left":"under","right":"below and in contact with"},{"id":4,"left":"over","right":"above and not touching"},{"id":5,"left":"at","right":"indicating a specific place or time"}]}'::jsonb, '2026-01-24 11:20:54.000+00', '2026-03-09 14:13:09.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (8, 15, 'fill_blank', 'In the sentence ''I have a lot of __________ to do today.'', what is the correct word to fill in the blank?', 'The correct word should be a noun that represents tasks or activities. In this case, ''tasks'' is appropriate.', '{"options":[{"id":"a","text":"tasks"},{"id":"b","text":"books"},{"id":"c","text":"friends"},{"id":"d","text":"dreams"}],"correctAnswers":["a"]}'::jsonb, '2026-02-16 15:01:39.000+00', '2026-03-07 15:15:57.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (9, 15, 'single_choice', 'Which of the following is the correct past tense form of the verb ''eat''?', 'The correct past tense form of ''eat'' is ''ate''.', '{"options":[{"id":"a","text":"ate"},{"id":"b","text":"eat"},{"id":"c","text":"eated"},{"id":"d","text":"eated"}],"correctAnswers":["a"]}'::jsonb, '2026-02-28 08:23:13.000+00', '2026-03-13 15:37:18.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (10, 7, 'ordering', 'Arrange the steps of making a cup of tea in the correct order.', 'The correct order is to boil water, add tea leaves, steep for a few minutes, and then strain the tea before adding milk and sugar.', '{"items":[{"text":"Boil water","order_id":1},{"text":"Add tea leaves","order_id":2},{"text":"Steep for a few minutes","order_id":3},{"text":"Strain the tea","order_id":4},{"text":"Add milk and sugar","order_id":5}]}'::jsonb, '2026-02-20 03:34:53.000+00', '2026-03-06 09:53:35.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (11, 8, 'true_false', 'Is the sentence ''She sells seashells by the seashore'' an example of alliteration?', 'Alliteration is the repetition of the same sound at the beginning of words in a phrase or sentence. In ''She sells seashells by the seashore'', the ''s'' sound is repeated at the beginning of multiple words.', '{"correctAnswer":true}'::jsonb, '2026-02-09 07:35:39.000+00', '2026-03-06 07:10:00.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (12, 7, 'matching', 'Match the following English phrasal verbs with their meanings.', 'Phrasal verbs are composed of a verb and a particle (preposition or adverb), and their meanings are often different from the literal meanings of their components.', '{"pairs":[{"id":1,"left":"look up","right":"find information in a book or on the internet"},{"id":2,"left":"take off","right":"start flying or become successful quickly"},{"id":3,"left":"put off","right":"postpone or delay"},{"id":4,"left":"give up","right":"stop trying or stop having a belief"},{"id":5,"left":"look down on","right":"consider someone or something as inferior"}]}'::jsonb, '2026-02-27 01:07:38.000+00', '2026-03-14 01:27:41.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (13, 11, 'multiple_choice', 'Which of the following is the correct past tense form of the verb ''eat''?', 'The correct past tense form of ''eat'' is ''ate''.', '{"options":[{"id":"a","text":"ate"},{"id":"b","text":"eat"},{"id":"c","text":"eaten"},{"id":"d","text":"eats"}],"correctAnswers":["a"]}'::jsonb, '2026-03-06 05:37:20.000+00', '2026-03-12 10:28:48.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (14, 4, 'multiple_choice', 'Which verb form is correct in the sentence: ''She ________ (go/went) to the store yesterday.''?', 'The correct verb form is ''went'' because the sentence refers to a past action.', '{"options":[{"id":"a","text":"go"},{"id":"b","text":"went"}],"correctAnswers":["b"]}'::jsonb, '2026-02-26 14:51:57.000+00', '2026-03-10 03:39:36.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (15, 15, 'true_false', 'The word ''definitely'' is an adverb that means ''certainly'' or ''without doubt''.', 'The word ''definitely'' is used to express certainty or strong confirmation, which is why it is classified as an adverb.', '{"correctAnswer":true}'::jsonb, '2026-02-22 06:09:54.000+00', '2026-03-07 03:02:51.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (16, 9, 'multiple_choice', 'Which sentence correctly uses the past simple tense?', 'The past simple tense is used to describe completed actions in the past. Option A describes an action that is completed, making it correct.', '{"options":[{"id":"a","text":"I went to the store yesterday."},{"id":"b","text":"I go to the store every day."},{"id":"c","text":"I am going to the store now."},{"id":"d","text":"I will go to the store later."}],"correctAnswers":["a"]}'::jsonb, '2026-02-15 09:58:31.000+00', '2026-03-05 08:54:53.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (17, 5, 'multiple_choice', 'Which sentence uses a correct past tense form of the verb ''write''?', 'The past tense of ''write'' is ''wrote''.', '{"options":[{"id":"a","text":"I wrote a letter yesterday."},{"id":"b","text":"I written a letter yesterday."},{"id":"c","text":"I write a letter yesterday."}],"correctAnswers":["a"]}'::jsonb, '2026-01-22 06:42:32.000+00', '2026-03-10 05:22:20.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (18, 14, 'matching', 'Match the correct prepositions with the sentences below.', 'Prepositions are used to describe the relationship between a noun or pronoun and other words in a sentence.', '{"pairs":[{"id":1,"left":"He is standing","right":"on the platform"},{"id":2,"left":"The book is lying","right":"on the table"},{"id":3,"left":"She is looking","right":"at the sky"},{"id":4,"left":"They are running","right":"through the forest"},{"id":5,"left":"The dog is sitting","right":"next to the tree"}]}'::jsonb, '2026-01-25 04:35:29.000+00', '2026-03-09 11:34:24.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (19, 5, 'flashcard', 'What is the past tense form of the verb ''to go''?', 'The past tense form of ''to go'' is ''went''.', '{"flashcard":{"front":"to go (past tense)","back":"went"}}'::jsonb, '2026-02-21 01:09:02.000+00', '2026-03-17 06:45:31.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (20, 7, 'ordering', 'Arrange the steps of making a cup of tea in the correct order.', 'The correct order is to boil water, add tea leaves, wait for a few minutes, then add milk and sugar to taste.', '{"ordering":[{"text":"Boil water","order_id":1},{"text":"Add tea leaves to the cup","order_id":2},{"text":"Wait for 3-5 minutes","order_id":3},{"text":"Add milk and sugar to taste","order_id":4}]}'::jsonb, '2026-01-18 11:26:20.000+00', '2026-03-04 05:35:15.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (21, 13, 'multiple_choice', 'Which of the following is the correct past tense form of the verb ''to go''?', 'The correct answer is ''went'' because it is the standard past tense form of ''to go''.', '{"options":[{"id":"a","text":"goed"},{"id":"b","text":"gone"},{"id":"c","text":"went"},{"id":"d","text":"going"}],"correctAnswers":["c"]}'::jsonb, '2026-02-24 02:56:02.000+00', '2026-03-04 09:03:37.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (22, 4, 'flashcard', 'What is the past tense form of the verb ''to go''?', 'The past tense form of ''to go'' is ''went''.', '{"flashcard":{"front":"went","back":"past tense of ''to go''"}}'::jsonb, '2026-01-27 04:58:27.000+00', '2026-03-11 01:23:03.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (23, 8, 'fill_blank', 'The __________ of the sentence is the part that expresses the main action or state of the sentence.', 'The predicate of the sentence is the part that expresses the main action or state of the sentence. It includes the verb and its complements.', '{"answers":["predicate"],"keywords":["sentence","main","action","state"]}'::jsonb, '2026-02-22 01:57:45.000+00', '2026-03-15 02:11:41.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (24, 15, 'true_false', 'The word ''disinterested'' means the same as ''uninterested''.', 'The term ''disinterested'' actually means impartial or unbiased, while ''uninterested'' means lacking interest.', '{"correctAnswer":false}'::jsonb, '2026-01-26 14:14:42.000+00', '2026-03-09 13:12:00.000+00');
INSERT INTO public.question ("id", "user_id", "type", "content", "explanation", "metadata", "created_at", "updated_at") VALUES (25, 14, 'true_false', 'The verb ''to be'' is only used in the present tense.', 'The verb ''to be'' is not limited to the present tense. It is also used in other tenses like past (was/were) and future (will be).', '{"correctAnswer":false}'::jsonb, '2026-01-22 04:08:00.000+00', '2026-02-27 11:37:05.000+00');
