INSERT INTO public.quiz ("id", "user_id", "title", "description", "visibility", "disabled", "note_id", "created_at", "updated_at") VALUES (1, 12, '"The Linguistic Labyrinth: A Journey Through English Learning"', 'Welcome to "The Linguistic Labyrinth: A Journey Through English Learning," a thrilling quiz that guides you through the intricate twists and turns of the English language. From vocabulary and grammar to idioms and cultural nuances, this quiz offers a comprehensive exploration of English, challenging your knowledge and enhancing your linguistic skills. Embark on this enlightening journey and discover the beauty and complexity of the English language.', 'private', FALSE, NULL, '2026-02-13 02:09:26.000+00', '2026-03-09 07:04:06.000+00');
INSERT INTO public.quiz ("id", "user_id", "title", "description", "visibility", "disabled", "note_id", "created_at", "updated_at") VALUES (2, 15, '"The Great English Adventure: Test Your Knowledge!"', 'Embark on "The Great English Adventure: Test Your Knowledge!" where you''ll explore the rich tapestry of the English language through an exciting quiz filled with vocabulary, grammar, idioms, and cultural insights. Challenge yourself with multiple-choice questions, fill-in-the-blanks, and even interactive scenarios. Perfect for language enthusiasts at all levels, this quiz promises a fun and engaging way to enhance your English skills and gain a deeper understanding of the language''s nuances.', 'private', FALSE, NULL, '2026-02-28 07:06:47.000+00', '2026-03-12 03:54:56.000+00');
INSERT INTO public.quiz ("id", "user_id", "title", "description", "visibility", "disabled", "note_id", "created_at", "updated_at") VALUES (3, 10, '"English Adventures: Test Your Knowledge with Trivia Treks"', 'Embark on a thrilling journey through the English language with "English Adventures: Test Your Knowledge with Trivia Treks". Dive into a series of captivating quizzes that explore the richness of vocabulary, the nuances of grammar, and the cultural significance of idioms. Each trivia trek is designed to challenge your linguistic skills and expand your understanding of the English language. From word origins to sentence structures, these quizzes offer a fun and educational experience for language enthusiasts at all levels.', 'private', FALSE, NULL, '2026-03-09 03:39:55.000+00', '2026-03-15 15:10:54.000+00');
INSERT INTO public.quiz ("id", "user_id", "title", "description", "visibility", "disabled", "note_id", "created_at", "updated_at") VALUES (4, 7, '"The Great English Adventure: Quiz Your Knowledge!"', 'Embark on "The Great English Adventure: Quiz Your Knowledge!" and put your linguistic skills to the test. This interactive quiz takes you on a journey through the English language, from basic grammar and vocabulary to advanced idioms and literature references. Test your understanding of tenses, prepositions, and spelling, and challenge yourself with questions on famous authors and literary works. Perfect for language enthusiasts and learners alike, this quiz is designed to make learning English fun and engaging.', 'private', FALSE, NULL, '2026-02-24 15:45:27.000+00', '2026-03-19 03:05:48.000+00');
INSERT INTO public.quiz ("id", "user_id", "title", "description", "visibility", "disabled", "note_id", "created_at", "updated_at") VALUES (5, 9, '"English Adventures: A Journey Through Language Learning"', '"English Adventures: A Journey Through Language Learning" is an engaging quiz designed to take learners on a captivating voyage through the English language. From exploring the origins of words and idioms to mastering grammar and vocabulary, this quiz offers a fun and interactive way to enhance language skills. Perfect for both beginners and advanced learners, it combines quizzes, puzzles, and games to make the learning process enjoyable and memorable.', 'public', FALSE, NULL, '2026-02-13 08:39:43.000+00', '2026-03-10 03:47:25.000+00');
INSERT INTO public.quiz ("id", "user_id", "title", "description", "visibility", "disabled", "note_id", "created_at", "updated_at") VALUES (6, 9, '"English Adventures: Test Your Skills and Unlock New Worlds"', 'Embark on an exciting journey through the English language with "English Adventures: Test Your Skills and Unlock New Worlds." This interactive quiz challenges you to explore various linguistic landscapes, from grammar and vocabulary to idioms and pronunciation. Each correct answer reveals a new adventure, expanding your language skills and knowledge while making learning fun and engaging. Dive in and discover a world of English possibilities!', 'private', FALSE, NULL, '2026-03-10 07:09:53.000+00', '2026-03-09 09:57:16.000+00');
INSERT INTO public.quiz ("id", "user_id", "title", "description", "visibility", "disabled", "note_id", "created_at", "updated_at") VALUES (7, 4, '"English Adventures: A Journey Through Language Learning"', 'Explore the enchanting world of English with "English Adventures: A Journey Through Language Learning." Embark on a thrilling quest to master new vocabulary, grammar, and idioms. From the bustling streets of London to the serene beaches of California, each level presents unique challenges and rewards, making your learning experience both fun and educational. Perfect for language enthusiasts at all levels, this quiz takes you on a vibrant adventure through the English language.', 'private', FALSE, 2, '2026-02-22 03:59:57.000+00', '2026-03-14 05:27:27.000+00');
INSERT INTO public.quiz ("id", "user_id", "title", "description", "visibility", "disabled", "note_id", "created_at", "updated_at") VALUES (8, 5, '"English Adventures: Test Your Language Skills!"', 'Welcome to "English Adventures: Test Your Language Skills!" Dive into an exciting journey where you''ll explore various aspects of the English language, from grammar and vocabulary to idioms and sentence structure. Each quiz question is designed to challenge and enhance your understanding of English in a fun and engaging way. Perfect for language learners at all levels, this quiz will take you on a linguistic adventure, testing your knowledge and helping you improve your skills. Ready to embark on this exciting journey? Let''s begin!', 'public', FALSE, 12, '2026-03-12 08:04:10.000+00', '2026-03-09 07:32:39.000+00');
INSERT INTO public.quiz ("id", "user_id", "title", "description", "visibility", "disabled", "note_id", "created_at", "updated_at") VALUES (9, 15, '"English Adventures: Journey Through Language Learning"', 'Explore the enchanting world of English with "English Adventures: Journey Through Language Learning," a captivating quiz that takes you on a thrilling expedition through the intricacies of the English language. From mastering vocabulary and grammar to improving your listening and speaking skills, this quiz is designed to be both educational and entertaining. Embark on this journey and discover the joy of language learning with each question and challenge.', 'private', FALSE, NULL, '2026-02-27 01:17:07.000+00', '2026-03-09 12:45:30.000+00');
INSERT INTO public.quiz ("id", "user_id", "title", "description", "visibility", "disabled", "note_id", "created_at", "updated_at") VALUES (10, 5, '"English Adventures: A Journey Through Language Learning"', 'English Adventures: A Journey Through Language Learning is an engaging quiz designed to take you on a thrilling voyage through the English language. From exploring the origins of words and idioms to mastering grammar rules and vocabulary, this quiz offers a comprehensive and interactive learning experience. Ideal for language enthusiasts and students alike, it promises to make your journey through the intricacies of English both enjoyable and enlightening.', 'public', FALSE, NULL, '2026-03-10 15:56:02.000+00', '2026-03-16 14:32:13.000+00');
