INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (1, 1, 1, '{"original_question_id":1,"type":"fill_blank","content":"The ___________ of the sentence is the part that expresses the main idea.","explanation":"The predicate of the sentence includes the verb and its complements, expressing the main action or state of the subject.","metadata":{"answers":["predicate"],"keywords":["sentence","main idea"]},"tags":[9,3]}'::jsonb, 1, '2026-03-14 11:23:26.000+00', '2026-03-19 01:11:26.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (2, 1, 21, '{"original_question_id":21,"type":"multiple_choice","content":"Which of the following is the correct past tense form of the verb ''to go''?","explanation":"The correct answer is ''went'' because it is the standard past tense form of ''to go''.","metadata":{"options":[{"id":"a","text":"goed"},{"id":"b","text":"gone"},{"id":"c","text":"went"},{"id":"d","text":"going"}],"correctAnswers":["c"]},"tags":[19]}'::jsonb, 2, '2026-03-17 15:19:14.000+00', '2026-03-16 01:40:08.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (3, 1, 6, '{"original_question_id":6,"type":"single_choice","content":"Which of the following words means ''to make something new or different''?","explanation":"The word ''innovate'' means to introduce new ideas, methods, or products, making something new or different.","metadata":{"options":[{"id":"a","text":"innovate"},{"id":"b","text":"interrupt"},{"id":"c","text":"inspire"},{"id":"d","text":"invent"}],"correctAnswers":["a"]},"tags":[20,2]}'::jsonb, 3, '2026-03-17 04:43:39.000+00', '2026-03-14 06:21:29.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (4, 1, 20, '{"original_question_id":20,"type":"ordering","content":"Arrange the steps of making a cup of tea in the correct order.","explanation":"The correct order is to boil water, add tea leaves, wait for a few minutes, then add milk and sugar to taste.","metadata":{"ordering":[{"text":"Boil water","order_id":1},{"text":"Add tea leaves to the cup","order_id":2},{"text":"Wait for 3-5 minutes","order_id":3},{"text":"Add milk and sugar to taste","order_id":4}]},"tags":[11,13,5]}'::jsonb, 4, '2026-03-17 13:13:06.000+00', '2026-03-19 05:17:34.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (5, 1, 8, '{"original_question_id":8,"type":"fill_blank","content":"In the sentence ''I have a lot of __________ to do today.'', what is the correct word to fill in the blank?","explanation":"The correct word should be a noun that represents tasks or activities. In this case, ''tasks'' is appropriate.","metadata":{"options":[{"id":"a","text":"tasks"},{"id":"b","text":"books"},{"id":"c","text":"friends"},{"id":"d","text":"dreams"}],"correctAnswers":["a"]},"tags":[18,16,20]}'::jsonb, 5, '2026-03-04 04:13:20.000+00', '2026-03-18 14:22:10.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (6, 2, 21, '{"original_question_id":21,"type":"multiple_choice","content":"Which of the following is the correct past tense form of the verb ''to go''?","explanation":"The correct answer is ''went'' because it is the standard past tense form of ''to go''.","metadata":{"options":[{"id":"a","text":"goed"},{"id":"b","text":"gone"},{"id":"c","text":"went"},{"id":"d","text":"going"}],"correctAnswers":["c"]},"tags":[19]}'::jsonb, 1, '2026-02-27 08:08:41.000+00', '2026-03-17 04:50:36.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (7, 2, 3, '{"original_question_id":3,"type":"ordering","content":"Arrange the following steps of the water cycle in the correct order: evaporation, precipitation, condensation, collection.","explanation":"The correct order of the water cycle is evaporation, condensation, precipitation, and collection. This is the natural sequence in which water moves through the environment.","metadata":{"type":"ordering","items":[{"text":"evaporation","order_id":1},{"text":"condensation","order_id":2},{"text":"precipitation","order_id":3},{"text":"collection","order_id":4}]},"tags":[20,10,3]}'::jsonb, 2, '2026-03-16 13:52:28.000+00', '2026-03-16 07:09:09.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (8, 2, 15, '{"original_question_id":15,"type":"true_false","content":"The word ''definitely'' is an adverb that means ''certainly'' or ''without doubt''.","explanation":"The word ''definitely'' is used to express certainty or strong confirmation, which is why it is classified as an adverb.","metadata":{"correctAnswer":true},"tags":[19,7]}'::jsonb, 3, '2026-03-10 02:35:33.000+00', '2026-03-19 11:18:07.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (9, 3, 16, '{"original_question_id":16,"type":"multiple_choice","content":"Which sentence correctly uses the past simple tense?","explanation":"The past simple tense is used to describe completed actions in the past. Option A describes an action that is completed, making it correct.","metadata":{"options":[{"id":"a","text":"I went to the store yesterday."},{"id":"b","text":"I go to the store every day."},{"id":"c","text":"I am going to the store now."},{"id":"d","text":"I will go to the store later."}],"correctAnswers":["a"]},"tags":[9,1]}'::jsonb, 1, '2026-03-17 09:00:42.000+00', '2026-03-17 08:57:58.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (10, 3, 2, '{"original_question_id":2,"type":"matching","content":"Match the English words with their meanings:","explanation":"Select the correct meaning for each word from the list.","metadata":{"pairs":[{"id":1,"left":"Amiable","right":"Friendly and pleasant"},{"id":2,"left":"Cacophony","right":"A harsh, unpleasant sound"},{"id":3,"left":"Furtive","right":"Done in a secretive or stealthy manner"},{"id":4,"left":"Lethargic","right":"Feeling or showing a lack of energy and enthusiasm"},{"id":5,"left":"Vex","right":"Trouble or annoy (someone)"}]},"tags":[9,4,20]}'::jsonb, 2, '2026-03-04 09:11:52.000+00', '2026-03-15 06:40:33.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (11, 3, 5, '{"original_question_id":5,"type":"matching","content":"Match the following English phrasal verbs with their meanings:","explanation":"The correct matches are based on the common meanings of the phrasal verbs.","metadata":{"type":"matching","pairs":[{"id":1,"left":"break down","right":"to fail or stop working"},{"id":2,"left":"turn down","right":"to refuse or reject"},{"id":3,"left":"hand in","right":"to submit or deliver"},{"id":4,"left":"look up","right":"to search for information"},{"id":5,"left":"take off","right":"to leave or depart"}]},"tags":[8,16,4]}'::jsonb, 3, '2026-03-13 05:29:59.000+00', '2026-03-14 08:32:43.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (12, 3, 8, '{"original_question_id":8,"type":"fill_blank","content":"In the sentence ''I have a lot of __________ to do today.'', what is the correct word to fill in the blank?","explanation":"The correct word should be a noun that represents tasks or activities. In this case, ''tasks'' is appropriate.","metadata":{"options":[{"id":"a","text":"tasks"},{"id":"b","text":"books"},{"id":"c","text":"friends"},{"id":"d","text":"dreams"}],"correctAnswers":["a"]},"tags":[18,16,20]}'::jsonb, 4, '2026-03-19 02:01:08.000+00', '2026-03-14 08:53:23.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (13, 3, 14, '{"original_question_id":14,"type":"multiple_choice","content":"Which verb form is correct in the sentence: ''She ________ (go/went) to the store yesterday.''?","explanation":"The correct verb form is ''went'' because the sentence refers to a past action.","metadata":{"options":[{"id":"a","text":"go"},{"id":"b","text":"went"}],"correctAnswers":["b"]},"tags":[3,1,6]}'::jsonb, 5, '2026-03-15 12:00:26.000+00', '2026-03-18 13:28:01.000+00');
INSERT INTO public.quiz_question ("id", "quiz_id", "original_question_id", "question_snapshot", "display_order", "created_at", "updated_at") VALUES (14, 3, 11, '{"original_question_id":11,"type":"true_false","content":"Is the sentence ''She sells seashells by the seashore'' an example of alliteration?","explanation":"Alliteration is the repetition of the same sound at the beginning of words in a phrase or sentence. In ''She sells seashells by the seashore'', the ''s'' sound is repeated at the beginning of multiple words.","metadata":{"correctAnswer":true},"tags":[14,5]}'::jsonb, 6, '2026-03-06 08:15:08.000+00', '2026-03-15 08:41:59.000+00');
