INSERT INTO public.explanation ("id", "user_id", "source_id", "text_range", "content", "author_type", "editable", "created_at", "updated_at") VALUES (1, 4, 9, '{"start":10,"end":143,"unit":"characters","text":"In the quiet of her study, Mia"}'::jsonb, 'The concept of "active vocabulary" refers to the words and phrases that a learner uses frequently and confidently in speaking and writing. Expanding active vocabulary is crucial for effective communication and reflects a deeper understanding of the language''s nuances.', 'user', TRUE, '2026-03-12 13:40:18.000+00', NULL);
INSERT INTO public.explanation ("id", "user_id", "source_id", "text_range", "content", "author_type", "editable", "created_at", "updated_at") VALUES (2, 10, 3, '{"start":15,"end":75,"unit":"characters","text":"1. Start with the basics: Focu"}'::jsonb, 'The concept of "Learning English Basics" primarily involves mastering fundamental skills such as vocabulary, grammar, and sentence structure, which are essential for effective communication in English. It also includes understanding cultural nuances and idiomatic expressions to improve fluency and comprehension.', 'user', TRUE, '2026-03-08 14:49:14.000+00', NULL);
INSERT INTO public.explanation ("id", "user_id", "source_id", "text_range", "content", "author_type", "editable", "created_at", "updated_at") VALUES (3, 10, 10, '{"start":26,"end":116,"unit":"characters","text":"The article discusses the impo"}'::jsonb, 'The source "Learn English Fundamentals Online" provides an accessible platform for learners to grasp basic English grammar, vocabulary, and pronunciation from home, offering flexibility and personalized learning paths. It covers essential concepts such as sentence structure, verb tenses, and common idioms, enhancing language proficiency through interactive exercises and multimedia content.', 'user', TRUE, '2026-02-28 10:49:36.000+00', '2026-03-15 01:33:52.000+00');
INSERT INTO public.explanation ("id", "user_id", "source_id", "text_range", "content", "author_type", "editable", "created_at", "updated_at") VALUES (4, 4, 3, '{"start":35,"end":97,"unit":"characters","text":"1. Start with the basics: Focu"}'::jsonb, 'Understanding the basic grammatical structures, such as sentence formation, verb tenses, and subject-verb agreement, is crucial for building a strong foundation in English. Practicing these fundamentals regularly helps improve overall language proficiency and communication skills.', 'user', TRUE, '2026-03-15 08:16:13.000+00', '2026-03-16 02:54:21.000+00');
INSERT INTO public.explanation ("id", "user_id", "source_id", "text_range", "content", "author_type", "editable", "created_at", "updated_at") VALUES (5, NULL, 10, '{"start":26,"end":142,"unit":"characters","text":"The article discusses the impo"}'::jsonb, 'The source "Learn English Fundamentals Online" focuses on providing basic English language skills such as grammar, vocabulary, and sentence structure through interactive online modules and exercises. This approach allows learners to practice and improve their English language abilities at their own pace from anywhere with internet access.', 'system', TRUE, '2026-02-27 09:08:21.000+00', '2026-03-15 07:03:50.000+00');
INSERT INTO public.explanation ("id", "user_id", "source_id", "text_range", "content", "author_type", "editable", "created_at", "updated_at") VALUES (6, 3, 4, '{"start":17,"end":120,"unit":"characters","text":"As I flipped through the pages"}'::jsonb, 'The concept of "phonetic transcription" explained in "Unlocking English: A Comprehensive Guide" involves using symbols to represent the sounds of English, helping learners to pronounce words more accurately by understanding how sounds are formed. This method is crucial for improving pronunciation and listening skills.', 'user', TRUE, '2026-03-14 14:59:37.000+00', '2026-03-18 03:02:38.000+00');
INSERT INTO public.explanation ("id", "user_id", "source_id", "text_range", "content", "author_type", "editable", "created_at", "updated_at") VALUES (7, NULL, 12, '{"start":7,"end":126,"unit":"characters","text":"1. Practice Regularly: Consist"}'::jsonb, 'The English Learning Journey is a structured path designed to help learners progress from beginner to advanced levels through consistent practice and exposure to the language. It typically includes various stages such as vocabulary building, grammar mastery, and fluency development, each tailored to enhance specific skills needed for effective communication in English.', 'system', TRUE, '2026-02-28 01:18:26.000+00', '2026-03-17 07:55:29.000+00');
INSERT INTO public.explanation ("id", "user_id", "source_id", "text_range", "content", "author_type", "editable", "created_at", "updated_at") VALUES (8, 6, 10, '{"start":14,"end":54,"unit":"characters","text":"The article discusses the impo"}'::jsonb, 'The concept of "Learn English Fundamentals Online" involves using digital platforms and resources to teach basic English skills such as grammar, vocabulary, and sentence structure to learners from various backgrounds at their own pace. This approach offers flexibility and accessibility, allowing students to improve their language skills whenever and wherever they have internet access.', 'user', TRUE, '2026-03-17 09:02:12.000+00', NULL);
INSERT INTO public.explanation ("id", "user_id", "source_id", "text_range", "content", "author_type", "editable", "created_at", "updated_at") VALUES (9, NULL, 8, '{"start":45,"end":138,"unit":"characters","text":"In the quiet of her study, Sar"}'::jsonb, '"Unlocking English" refers to a method that breaks down complex grammatical structures and vocabulary into manageable components to help learners understand and apply them effectively. This approach emphasizes interactive and context-rich learning experiences to enhance comprehension and fluency.', 'system', TRUE, '2026-03-09 11:18:57.000+00', '2026-03-16 08:34:53.000+00');
INSERT INTO public.explanation ("id", "user_id", "source_id", "text_range", "content", "author_type", "editable", "created_at", "updated_at") VALUES (10, NULL, 4, '{"start":28,"end":127,"unit":"characters","text":"As I flipped through the pages"}'::jsonb, 'The concept of phonetic transcription in "Unlocking English: A Comprehensive Guide" involves using symbols to represent the sounds of speech, helping learners to pronounce English words correctly by relating them to their phonetic equivalents. This technique is crucial for improving pronunciation and understanding spoken English.', 'system', TRUE, '2026-02-28 01:03:53.000+00', '2026-03-16 09:52:00.000+00');
